VALUES
  ('judicial-57f41407-moex-00713', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲以乙為被告向民事法院提起訴訟，關於民事法院與行政法院之審判權限，下列敘述，何者錯誤？', '["若甲先前曾就同一事件向行政法院提起訴訟，行政法院認為無審判權而裁定駁回確定，甲又向民事法院 起訴，民事法院若認為其無審判權，應裁定停止訴訟，並聲請司法院大法官解釋", "若民事法院認為其無審判權，應依職權裁定將訴訟移送至有受理訴訟權限之管轄法院", "若乙抗辯該事件為行政爭訟事件，民事法院應先為裁定", "若該訴訟已先行繫屬於行政法院時，甲就同一事件得向民事法院更行起訴"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 26, "answer_corrected": true, "flags": ["answer_corrected_skip_v1"], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00714', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '依民事訴訟法規定，下列關於民事訴訟程序上訴第三審之敘述，何者正確？', '["上訴第三審得以原判決事實認定有誤為理由而為之", "就第一審法院之判決，縱經當事人合意，亦不得直接上訴第三審法院", "第二審判決送達後，當事人應於15日內提起上訴，始為合法", "對於財產權關係訴訟之第二審判決，如其上訴利益為40萬元者，不得上訴第三審"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00715', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '關於民事訴訟上和解之效力，下列敘述，何者正確?', '["和解有無效或得撤銷之原因時，當事人得於和解成立之日起30日內，請求繼續審判", "當事人就未聲明之事項成立訴訟上和解，不生任何效力", "對於已成立之和解，當事人如有爭執，仍得向上級審法院提起上訴", "已成立之和解，應經法院認證，始取得執行力"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00716', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲、乙、丙三人於2020年初與丁旅遊公司訂立旅遊契約，預計於同年5月前往美國10日遊，並支付團費 新臺幣（下同）21萬元。然其後卻因全球爆發嚴重特殊傳染性肺炎導致無法出國。甲、乙、丙請求丁退費， 但丁於完成一部（1萬元）退款後，即置之不理。甲、乙、丙欲起訴向丁請求剩餘之退款，應適用何種訴 訟程序救濟？', '["普通訴訟程序", "簡易訴訟程序", "再審訴訟程序", "第三人撤銷訴訟程序"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00717', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲將Ａ地連同其上Ｂ屋及獨立車庫C出賣於乙，並移轉所有權。本案中涉及幾個物權行為？', '["一個", "二個", "三個", "四個"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00718', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '興建中之房屋，只完成樑柱而無屋頂，其性質為何？', '["定著物", "土地", "動產", "權利"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00719', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲女未婚生下一女乙，乙女成年後，與丙男結婚，但丙卻愛上甲。乙為成全甲丙，而與丙離婚。甲丙若結 婚，其婚姻之效力如何？', '["有效", "無效", "效力未定", "得撤銷"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00720', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '婚生子女於何種情形時，得從母姓？', '["於出生時有書面約定並登記即可", "母無兄弟", "僅有一名子女", "已有其他從父姓之子女"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00721', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '甲喪偶有乙、丙、丁三子。乙婚後生有一子戊。乙先於甲死亡。甲病危時，丙隨侍在側，但也隱匿甲貴重 之財產，於甲死亡後被發現。甲之繼承人為何？', '["僅丙、丁", "僅戊、丁", "僅丙、戊", "丙、丁、戊"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL),
  ('judicial-57f41407-moex-00722', 'judicial-57f41407', 'judicial-57f41407-moex-111-55d283b0', 'sub-judicial-57f41407-04', NULL, 'single_choice', '下列關於期日與期間之敘述，何者錯誤？', '["稱月或年者，依曆計算", "以時定期間者，即時起算", "以日、星期、月或年定期間者，以期間末日之次日，為期間之終止", "於一定期日或期間內，應為意思表示或給付者，其期日或其期間之末日，為星期日、紀念日或其他休息 日時，以其休息日之次日代之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:26:41+00:00", "source_pdf_sha1": "c66d3519d6ba", "answer_pdf_sha1": "15aa6844e2c8", "source_family": "moex-gov-tw", "moex": {"exam_code": "111130", "c": "301", "s": "0318", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "111", "exam_name": "111年公務人員特種考試司法人員考試、法務部調查局調查人員考試、海岸巡防人員考試、移民行政人員考試、未具擬任職務任用資格取得法官遴選資格考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "judicial", "civil_category": "錄事"}'::jsonb, NULL)
